// MARK: - Native handlers

extension HybridWebViewController {

    private func handleCameraRequestPermission(requestId: String) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        switch status {
        case .authorized:
            sendResolve(requestId: requestId, result: ["status": "authorized"])
        case .denied:
            sendResolve(requestId: requestId, result: ["status": "denied"])
        case .restricted:
            sendResolve(requestId: requestId, result: ["status": "restricted"])
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendResolve(requestId: requestId, result: ["status": granted ? "authorized" : "denied"])
                }
            }
        @unknown default:
            sendReject(requestId: requestId, code: "unknown", message: "Unknown camera authorization status")
        }
    }

    private func handlePushRequestPermission(requestId: String) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendReject(requestId: requestId, code: "push_error", message: error.localizedDescription)
                    return
                }
                UIApplication.shared.registerForRemoteNotifications()
                self?.sendResolve(requestId: requestId, result: ["granted": granted])
            }
        }
    }

    private func handlePushGetStatus(requestId: String) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            DispatchQueue.main.async {
                let status: String
                switch settings.authorizationStatus {
                case .authorized: status = "authorized"
                case .denied: status = "denied"
                case .notDetermined: status = "not_determined"
                case .provisional: status = "provisional"
                case .ephemeral: status = "ephemeral"
                @unknown default: status = "unknown"
                }
                self?.sendResolve(requestId: requestId, result: ["status": status])
            }
        }
    }

    private func handleIAPCanMakePayments(requestId: String) {
        sendResolve(requestId: requestId, result: ["canMakePayments": SKPaymentQueue.canMakePayments()])
    }

    private func handleIAPPurchase(requestId: String, productId: String?) {
        guard let productId, !productId.isEmpty else {
            sendReject(requestId: requestId, code: "invalid_args", message: "Missing productId")
            return
        }
        sendReject(requestId: requestId, code: "not_implemented", message: "IAP purchase flow requires StoreKit 2 product fetch and transaction handling in your app.")
    }

    private func handleIAPRestore(requestId: String) {
        sendReject(requestId: requestId, code: "not_implemented", message: "IAP restore flow requires StoreKit 2 transaction sync/restore handling in your app.")
    }
}